inline constexpr std::size_t kStateVarCount = 4567;

/// Binary search by var_id. Returns nullptr if not named.
inline const StateVar* FindStateVar(uint32_t var_id) noexcept {
    std::size_t lo = 0, hi = kStateVarCount;
    while (lo < hi) {
        std::size_t mid = (lo + hi) / 2;
        if (kStateVars[mid].var_id == var_id) return &kStateVars[mid];
        if (kStateVars[mid].var_id < var_id) lo = mid + 1;
        else hi = mid;
    }
    return nullptr;
}

inline const char* StateVarName(uint32_t var_id) noexcept {
    const auto* v = FindStateVar(var_id);
    return v ? v->name : "?";
}

inline bool IsKnownStateVar(uint32_t var_id) noexcept {
    return FindStateVar(var_id) != nullptr;
}

inline bool IsStatusVar(uint32_t var_id) noexcept {
    const auto* v = FindStateVar(var_id);
    return v && (v->kind == StateVarKind::Status || v->kind == StateVarKind::Both);
}

inline bool IsValueVar(uint32_t var_id) noexcept {
    const auto* v = FindStateVar(var_id);
    return v && (v->kind == StateVarKind::Value || v->kind == StateVarKind::Both);
}

inline const char* KindName(StateVarKind k) noexcept {
    switch (k) {
    case StateVarKind::Status: return "Status";
    case StateVarKind::Value: return "Value";
    case StateVarKind::Both: return "Both";
    case StateVarKind::Unknown: return "Unknown";
    }
    return "?";
}

inline const char* DomainName(StateVarDomain d) noexcept {
    switch (d) {
    case StateVarDomain::ABILITY_STATE: return "ABILITY_STATE";
    case StateVarDomain::ABILITY_COOLDOWN: return "ABILITY_COOLDOWN";
    case StateVarDomain::BUFF_BENEFIT: return "BUFF_BENEFIT";
    case StateVarDomain::DEBUFF_HOSTILE: return "DEBUFF_HOSTILE";
    case StateVarDomain::DAMAGE_MODIFIER: return "DAMAGE_MODIFIER";
    case StateVarDomain::HITBOX_DEFLECT: return "HITBOX_DEFLECT";
    case StateVarDomain::HEALTH_POOL: return "HEALTH_POOL";
    case StateVarDomain::SHIELD_BARRIER: return "SHIELD_BARRIER";
    case StateVarDomain::CHASE_VAR: return "CHASE_VAR";
    case StateVarDomain::STACK: return "STACK";
    case StateVarDomain::WEAPON_PARAM: return "WEAPON_PARAM";
    case StateVarDomain::ULT_CHARGE: return "ULT_CHARGE";
    case StateVarDomain::POSITION: return "POSITION";
    case StateVarDomain::PHYSICS: return "PHYSICS";
    case StateVarDomain::EFFECT: return "EFFECT";
    case StateVarDomain::UI_UX: return "UI_UX";
    case StateVarDomain::TEAM: return "TEAM";
    case StateVarDomain::LIFECYCLE: return "LIFECYCLE";
    case StateVarDomain::UNCLASSIFIED: return "UNCLASSIFIED";
    }
    return "?";
}

inline const StateVar* StateVarsBegin() noexcept { return kStateVars; }
inline const StateVar* StateVarsEnd()   noexcept { return kStateVars + kStateVarCount; }

